// srad_kernel.cu
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include "srad.h"

__global__ void srad_step1_kernel(float *J, float *dN, float *dS, float *dW, float *dE, float *c, int rows, int cols, int r1, int r2, int c1, int c2, float q0sqr) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;
        float Jc = J[k];

        // directional derivates
        dN[k] = J[(i > 0 ? i - 1 : 0) * cols + j] - Jc;
        dS[k] = J[(i < rows - 1 ? i + 1 : rows - 1) * cols + j] - Jc;
        dW[k] = J[i * cols + (j > 0 ? j - 1 : 0)] - Jc;
        dE[k] = J[i * cols + (j < cols - 1 ? j + 1 : cols - 1)] - Jc;

        float G2 = (dN[k] * dN[k] + dS[k] * dS[k] + dW[k] * dW[k] + dE[k] * dE[k]) / (Jc * Jc);
        float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

        float num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
        float den = 1 + (.25 * L);
        float qsqr = num / (den * den);

        // diffusion coefficent (equ 33)
        den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
        c[k] = 1.0 / (1.0 + den);

        // saturate diffusion coefficent
        if (c[k] < 0) {
            c[k] = 0;
        } else if (c[k] > 1) {
            c[k] = 1;
        }
    }
}

__global__ void srad_step2_kernel(float *J, float *dN, float *dS, float *dW, float *dE, float *c, int rows, int cols, float lambda) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int i = blockIdx.y * blockDim.y + threadIdx.y;

    if (i < rows && j < cols) {
        int k = i * cols + j;

        // diffusion coefficent
        float cN = c[k];
        float cS = c[(i < rows - 1 ? i + 1 : rows - 1) * cols + j];
        float cW = c[k];
        float cE = c[i * cols + (j < cols - 1 ? j + 1 : cols - 1)];

        // divergence (equ 58)
        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

        // image update (equ 61)
        J[k] = J[k] + 0.25 * lambda * D;
    }
}

void srad_cuda(float *I_host, float *J_host, int rows, int cols, int r1, int r2, int c1, int c2, float lambda, int niter) {
    int size_I = rows * cols;
    int size_R = (r2 - r1 + 1) * (c2 - c1 + 1);
    float *I_dev, *J_dev, *dN_dev, *dS_dev, *dW_dev, *dE_dev, *c_dev;
    float q0sqr, sum, sum2, tmp, meanROI, varROI;

    // Allocate memory on the device
    cudaMalloc(&I_dev, size_I * sizeof(float));
    cudaMalloc(&J_dev, size_I * sizeof(float));
    cudaMalloc(&dN_dev, size_I * sizeof(float));
    cudaMalloc(&dS_dev, size_I * sizeof(float));
    cudaMalloc(&dW_dev, size_I * sizeof(float));
    cudaMalloc(&dE_dev, size_I * sizeof(float));
    cudaMalloc(&c_dev, size_I * sizeof(float));

    // Copy input data from host to device
    cudaMemcpy(I_dev, I_host, size_I * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(J_dev, J_host, size_I * sizeof(float), cudaMemcpyHostToDevice);

    dim3 blockDim(BLOCK_SIZE, BLOCK_SIZE);
    dim3 gridDim((cols + blockDim.x - 1) / blockDim.x, (rows + blockDim.y - 1) / blockDim.y);

    for (int iter = 0; iter < niter; ++iter) {
        sum = 0;
        sum2 = 0;
        // Calculate ROI statistics on host (can be optimized to GPU if needed)
        for (int i = r1; i <= r2; ++i) {
            for (int j = c1; j <= c2; ++j) {
                tmp = J_host[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        // Transfer q0sqr to device if it's used in the kernel
        // For simplicity, we'll pass it as an argument. If it were large, we'd use a constant memory.

        // Step 1: Calculate diffusion coefficients
        srad_step1_kernel<<<gridDim, blockDim>>>(J_dev, dN_dev, dS_dev, dW_dev, dE_dev, c_dev, rows, cols, r1, r2, c1, c2, q0sqr);
        cudaDeviceSynchronize();
        cudaError_t err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "CUDA error in srad_step1_kernel: %s\n", cudaGetErrorString(err));
            exit(1);
        }

        // Step 2: Update the image
        srad_step2_kernel<<<gridDim, blockDim>>>(J_dev, dN_dev, dS_dev, dW_dev, dE_dev, c_dev, rows, cols, lambda);
        cudaDeviceSynchronize();
        err = cudaGetLastError();
        if (err != cudaSuccess) {
            fprintf(stderr, "CUDA error in srad_step2_kernel: %s\n", cudaGetErrorString(err));
            exit(1);
        }

        // Copy J_dev back to J_host for ROI calculation in the next iteration
        cudaMemcpy(J_host, J_dev, size_I * sizeof(float), cudaMemcpyDeviceToHost);
    }

    // Copy the final result from device to host
    cudaMemcpy(J_host, J_dev, size_I * sizeof(float), cudaMemcpyDeviceToHost);

    // Free memory on the device
    cudaFree(I_dev);
    cudaFree(J_dev);
    cudaFree(dN_dev);
    cudaFree(dS_dev);
    cudaFree(dW_dev);
    cudaFree(dE_dev);
    cudaFree(c_dev);
}
